      12:{q:"Aşırı boyutlu bir yük genelde neyle işaretlenir?",options:["Sadece mavi ışıkla","Bayraklar ve 'OVERSIZE LOAD' tabelaları","Hiçbir işaret olmadan","Tek küçük bir reflektör ile"],explanation:"Aşırı boyutlu yük bayraklar ve 'OVERSIZE LOAD' tabelalarıyla işaretlenir."},
      13:{q:"Bir CMV sürerken mesajlaşmak (texting) nasıldır?",options:["Düşük hızda serbest","Yasak","Yavaş trafikte sorun değil","Sadece geceleri yasak"],explanation:"CMV sürerken mesajlaşmak yasaktır."},
      14:{q:"Servis dışı (OOS) bırakılmış bir CMV ne yapILMAMAlı?",options:["Yıkanmamalı","Onarılana kadar sürülmemeli","Otoparka park edilmemeli","Tekrar muayene edilmemeli"],explanation:"Servis dışı bırakılan araç onarılana kadar sürülmemeli."},
      15:{q:"Görev durumu kaydın (logbook) nasıl olmalı?",options:["Çoğunlukla boş bırakılmış","Güncel ve doğru tutulmuş","Aylık doldurulmuş","Tamamen isteğe bağlı"],explanation:"Logbook güncel ve doğru tutulmalı."},
      16:{q:"İzinsiz hangisi bir Texas boyut/ağırlık sınırı DEĞİLDİR?",options:["102 inç genişlik","Sınırsız ağırlık","14 feet yükseklik","80,000 lb brüt"],explanation:"'Sınırsız ağırlık' bir sınır değildir; izinsiz azami 80,000 lb'dir."},
      17:{q:"Zorunlu acil donanım neleri içerir?",options:["Uyarı üçgenleri","Bir yangın söndürücü","Yedek elektrik sigortaları","Hepsi"],explanation:"Uyarı üçgenleri, söndürücü ve yedek sigortalar — hepsi."},
      18:{q:"Tabelalı bir ağırlık sınırını yok saymak için yasal sebep hangisidir?",options:["Acelen olması","Yükünün değerli olması","Köprünün sağlam görünmesi","Hiçbiri"],explanation:"Tabelalı ağırlık sınırını yok saymanın yasal sebebi yoktur."},
      19:{q:"Ömür boyu uyuşturucu-suçu diskalifiyesi sonrası CDL'in nasıldır?",options:["30 günde geri gelir","Asla iade edilmez","1 yılda geri gelir","Bir kurstan sonra gelir"],explanation:"Uyuşturucu-suçu ömür boyu diskalifiyesinde CDL asla iade edilmez."}
