    {
      0:{q:"Если на шоссе Техаса нет особого лимита для грузовиков, лимит скорости грузовика:",options:["Всегда 45 миль/ч","По знаку (указанный лимит)","Всегда 70 миль/ч","Без ограничений там"],explanation:"Если нет особого лимита для грузовиков, соблюдай указанный лимит."},
      1:{q:"На пешеходном переходе нужно:",options:["Посигналить и ехать","Уступить пешеходам","Ускориться, чтобы проехать","Перекрыть зону перехода"],explanation:"На переходе уступи пешеходам."},
      2:{q:"В школьной зоне нужно:",options:["Держать обычную скорость","Снизить до лимита школьной зоны","Часто сигналить","Обгонять другие машины"],explanation:"В школьной зоне снизь до указанного лимита."},
      3:{q:"Тихоходные грузовики обычно должны:",options:["Ехать в левом ряду","Держаться правого ряда","Занимать два ряда","Довольно часто останавливаться"],explanation:"Тихоходные грузовики держатся правого ряда."},
      4:{q:"Остановившись на обочине, нужно включить:",options:["Дальний свет","Аварийку (четыре поворотника)","Свет в салоне","Только левый поворотник"],explanation:"На обочине включи аварийку."},
      5:{q:"Поворот направо на красный разрешён только после того, как ты:",options:["Немного снизишь скорость","Полностью остановишься и путь чист","Дважды посигналишь","Мигнёшь фарами"],explanation:"Полностью остановись; если чисто, можно повернуть направо на красный (если не запрещено)."},
      6:{q:"В Техасе ремень безопасности должен пристёгивать:",options:["Только сам водитель машины","Водитель и передние пассажиры","Только в ночное время","Никто в грузовике вообще"],explanation:"Водитель и передние пассажиры должны пристёгиваться."},
      7:{q:"Открытая ёмкость с алкоголем в кабине CMV:",options:["Можно, если закрыта","Запрещена","Можно, если пуста","Лишь предупреждение"],explanation:"Открытая ёмкость с алкоголем в кабине CMV запрещена."},
      8:{q:"Груз сверх законных размеров или веса требует:",options:["Ничего лишнего","Специального разрешения","Только маленького флажка","Всегда полицейского эскорта"],explanation:"Груз сверх лимитов требует специального разрешения."},
      9:{q:"Указанный на знаке предел веса моста должен:",options:["Игнорироваться, если легко","Соблюдаться всегда","Считаться лишь ориентиром","Удваиваться для грузовиков"],explanation:"Указанный предел веса моста нужно соблюдать всегда."},
      10:{q:"Очень широкий груз по закону может требовать:",options:["Второго двигателя","Машину сопровождения (пилот)","Никаких обозначений","Тормоза прицепа"],explanation:"Очень широкий груз может требовать машину сопровождения."},
      11:{q:"Движение негабаритного груза может быть ограничено:",options:["Только полночью","Определёнными дневными часами","Только по выходным","Всегда, в любое время"],explanation:"Движение негабарита может ограничиваться определёнными дневными часами."},
      12:{q:"Негабаритный груз обычно обозначают:",options:["Только синим светом","Флажками и знаками 'OVERSIZE LOAD'","Без обозначений вовсе","Одним маленьким отражателем"],explanation:"Негабарит обозначают флажками и знаками 'OVERSIZE LOAD'."},
      13:{q:"Писать сообщения за рулём CMV:",options:["Можно на малой скорости","Запрещено","Можно в медленной пробке","Запрещено только ночью"],explanation:"Писать сообщения за рулём CMV запрещено."},
      14:{q:"CMV, выведенный из эксплуатации (OOS), нельзя:",options:["Мыть или чистить","Водить до ремонта","Парковать на стоянке","Снова осматривать"],explanation:"ТС, выведенное из эксплуатации, нельзя водить до ремонта."},
      15:{q:"Твой учёт режима труда (logbook) должен быть:",options:["В основном пустым","Актуальным и точным","Заполнен раз в месяц","Совершенно по желанию"],explanation:"Logbook должен быть актуальным и точным."},
      16:{q:"Что НЕ является техасским пределом размера/веса без разрешения?",options:["Ширина 102 дюйма","Неограниченный вес","Высота 14 футов","80 000 фунтов брутто"],explanation:"'Неограниченный вес' — не предел; без разрешения максимум 80 000 фунтов."},
      17:{q:"Обязательное аварийное снаряжение включает:",options:["Знаки аварийной остановки","Огнетушитель","Запасные электрические предохранители","Всё перечисленное"],explanation:"Знаки, огнетушитель и запасные предохранители — всё это."},
      18:{q:"Какая причина законно игнорировать указанный предел веса?",options:["Ты торопишься","Твой груз ценный","Мост выглядит прочным","Ничего из перечисленного"],explanation:"Нет законной причины игнорировать указанный предел веса."},
      19:{q:"После пожизненной дисквалификации за наркопреступление твои права:",options:["Вернут через 30 дней","Никогда не восстановят","Вернут через 1 год","Вернут после курса"],explanation:"При пожизненной дисквалификации за наркопреступление права не восстанавливают."}
    }
