      3:{q:"Sınıf 4 tehlikeli maddeler nedir?",options:["Yanıcı katılar","Yanıcı sıvılar","Patlayıcı maddeler","Aşındırıcı sıvılar"],explanation:"Sınıf 4 yanıcı katılardır."},
      4:{q:"Sınıf 5 tehlikeli maddeler nedir?",options:["Oksitleyiciler ve organik peroksitler","Patlayıcı katı maddeler","Sıkıştırılmış basınçlı gazlar","Çeşitli sıvı zehirler"],explanation:"Sınıf 5 oksitleyiciler ve organik peroksitlerdir."},
