      5:{q:"Bir dağ yolunda küçük vitesi ne zaman kullanmalısın?",options:["Sadece çıkarken","Dik bir inişten inerken","Hiçbir zaman","Düz kısımlarda"],explanation:"Dik bir inişten inerken küçük vites kullan."},
      6:{q:"Kaçış kamyon rampaları genelde nerede bulunur?",options:["Yoğun şehir caddelerinde","Uzun dik inişlerde","Düz açık otoyollarda","Büyük otoparklarda"],explanation:"Kaçış rampaları uzun dik inişlerde bulunur."},
      7:{q:"Gece bir virajdan önce ne yapmalısın?",options:["İyice hızlanıp gitmeli","Daha az ileriyi göremediğin için yavaşlamalı","Tüm ışıkları kapatmalı","Siste uzun farları kullanmalı"],explanation:"Gece daha az ileriyi gördüğün için viraj öncesi yavaşla."},
      8:{q:"Frenlerin çalıştığını kontrol etmek için seferden önce ne yapmalısın?",options:["Sadece atlamalı","Düşük hızda test etmeli","Otoyolda aniden basmalı","Hiç test etmemeli"],explanation:"Frenleri düşük hızda test et."},
      9:{q:"Direksiyondaki doğru el konumu nedir?",options:["Tek el aşağıda","İki el, sağlam tutuş","Kısa süre elsiz","Sadece tek parmak"],explanation:"İki el ile sağlam tutuş doğru konumdur."},
      10:{q:"Geri geri sürmen gerektiğinde en güvenli yön hangisidir?",options:["Kör tarafa doğru","Sürücü tarafına doğru","Sadece dümdüz geri","Herhangi bir yön"],explanation:"Sürücü tarafına doğru geri gitmek en güvenlisidir."},
      11:{q:"Bir aracın durma mesafesi neyle artar?",options:["Düşük hızla","Yüksek hızla","Daha hafif yükle","İyi frenlerle"],explanation:"Durma mesafesi yüksek hızla artar."},
      12:{q:"Bir otoyola katılmak için ne yapmalısın?",options:["Durup orada beklemeli","Trafik hızına uyup bir boşluğa katılmalı","Zorla içeri girip girmeli","Çok yavaş şekilde sürmeli"],explanation:"Trafik hızına uy ve bir boşluğa katıl."},
      13:{q:"Kornanı ne zaman kullanmalısın?",options:["Arkadaşlarını selamlamak için","Sadece başkalarını tehlikeye karşı uyarmak için","Sürerken sürekli olarak çalmak için","Sadece vakit geçirmek için"],explanation:"Kornayı sadece başkalarını tehlikeye karşı uyarmak için kullan."},
      14:{q:"Yokuş aşağı bir yere park ederken tekerleklerini nereye çevirmelisin?",options:["Yola doğru","Kaldırıma doğru","Dümdüz ileri","Fark etmez"],explanation:"Yokuş aşağı park ederken tekerlekleri kaldırıma çevir."},
      15:{q:"Tekerleklerin sağ bankete kayarsa ne yapmalısın?",options:["Direksiyonu geri sarsmalı","Gazdan çekip yumuşakça geri dönmeli","Çok sert frenlemeli","Toparlamak için hızlanmalı"],explanation:"Gazdan çek ve yumuşakça yola geri dön."},
      16:{q:"Bir takipçiyle baş etmenin en güvenli yolu nedir?",options:["Aniden frenlemek","Kenara geçip onu geçirmek","Bir hayli hızlanmak","Onu bilerek engellemek"],explanation:"Kenara geç ve onu geçmesine izin ver."},
      17:{q:"İyi bir sürücü nasıl iletişim kurar?",options:["Bir hayli korna çalarak","Niyetlerini açıkça sinyalle bildirerek","Uzun far çakarak","Sadece çok hızlı sürerek"],explanation:"Niyetlerini açıkça sinyalle bildirerek iletişim kur."}
