      2:{q:"35 mph giden 30 ft uzunluğundaki bir araç kaç saniye takip mesafesi ister?",options:["2 saniye","3 saniye","4 saniye","5 saniye"],explanation:"30÷10=3; 40 altı = 3 saniye."},
      3:{q:"55 mph giden 30 ft uzunluğundaki bir araç kaç saniye takip mesafesi ister?",options:["3 saniye","4 saniye","5 saniye","2 saniye"],explanation:"30÷10=3, 40 üstü +1 = 4 saniye."},
