      5:{q:"50 mph giden 60 ft uzunluğundaki bir araç kaç saniye takip mesafesi ister?",options:["6 saniye","7 saniye","8 saniye","5 saniye"],explanation:"60÷10=6, 40 üstü +1 = 7 saniye."},
      6:{q:"55 mph giden 70 ft uzunluğundaki bir araç kaç saniye takip mesafesi ister?",options:["7 saniye","8 saniye","9 saniye","6 saniye"],explanation:"70÷10=7, 40 üstü +1 = 8 saniye."},
      7:{q:"35 mph giden 90 ft uzunluğundaki bir araç kaç saniye takip mesafesi ister?",options:["8 saniye","9 saniye","10 saniye","11 saniye"],explanation:"90÷10=9; 40 altı = 9 saniye."},
      8:{q:"60 mph giden 90 ft uzunluğundaki bir araç kaç saniye takip mesafesi ister?",options:["9 saniye","10 saniye","11 saniye","8 saniye"],explanation:"90÷10=9, 40 üstü +1 = 10 saniye."},
      9:{q:"35 mph giden 100 ft uzunluğundaki bir araç kaç saniye takip mesafesi ister?",options:["9 saniye","10 saniye","11 saniye","12 saniye"],explanation:"100÷10=10; 40 altı = 10 saniye."},
      10:{q:"45 mph giden 100 ft uzunluğundaki bir araç kaç saniye takip mesafesi ister?",options:["10 saniye","11 saniye","12 saniye","9 saniye"],explanation:"100÷10=10, 40 üstü +1 = 11 saniye."},
      11:{q:"60 mph giden 60 ft uzunluğundaki bir araç kaç saniye takip mesafesi ister?",options:["6 saniye","7 saniye","8 saniye","5 saniye"],explanation:"60÷10=6, 40 üstü +1 = 7 saniye."},
      12:{q:"Bir geyik aniden kamyonunun hemen önündeki yola fırlıyor. Genelde en güvenlisi nedir?",options:["Sertçe yan şeride kaçmak","Sağlam frenleyip kendi şeridinde kalmak","Geçmek için hızlanmak","İki elini direksiyondan çekmek"],explanation:"Frenleyip şeritte kalmak, devrilebilecek büyük bir kamyonu sertçe kaçırmaktan güvenlidir."},
      13:{q:"Hız limiti düşük bir otoyol çalışma alanına giriyorsun. Ne yapmalısın?",options:["Tam otoyol seyir hızını korumak","Çalışma alanı limitine inip işçilere dikkat etmek","Tüm yavaş arabaları sollayıp geçmek","Uzun farları yakıp kullanmak"],explanation:"Çalışma alanı hızına in ve işçilere/ekipmana dikkat et."},
      14:{q:"Çekiş tekerlerin bir virajda kaymaya başlıyor. Ne yapmalısın?",options:["Gittikçe daha sert şekilde frenlemek","Gazdan çekip gitmek istediğin yöne direksiyon kırmak","Hızla ters yöne direksiyon kırmak","Gaza sertçe basmak"],explanation:"Gazdan çek ve gitmek istediğin yöne direksiyon kırarak düzel."},
      15:{q:"Beklediğinden daha keskin bir viraja giriyorsun. Ne yapmalısın?",options:["Tam ortasında sert şekilde frenlemek","Virajdan önce yavaşlamak, içinde sert frenlememek","Viraj boyunca sürekli hızlanmak","Boşta savrularak geçip gitmek"],explanation:"Virajdan önce yavaşla; viraj içinde sert frenleme kayma/devrilmeye yol açar."},
      16:{q:"Ağır kamyonun yaklaşırken trafik ışığı sarıya dönüyor. Ne yapmalısın?",options:["Sertçe frene basmak","Güvenle duramıyorsan dikkatle devam etmek","Limitin epey üstüne çıkmak","Kavşağın ortasında durmak"],explanation:"Güvenle duramıyorsan dikkatle devam et; sert frenleme."},
      17:{q:"Önündeki araç aniden frenledi ve az kalsın çarpıyordun. Şunu yapmış olmalıydın:",options:["Bir hayli daha hızlı sürmek","Güvenli bir takip mesafesi tutmak","Daha yakından takip etmek","Telefonuna bakmak"],explanation:"Güvenli takip mesafesi sana tepki için zaman verir."},
      18:{q:"Gece tanımadığın bir yolda ilk kez sürüyorsun. Ne yapmalısın?",options:["Öğrenmek için daha hızlı sürmek","Yavaşlayıp farlarını iyi kullanmak","Işıkları kapatmak","Bir arabayı yakından takip etmek"],explanation:"Gece tanımadığın yolda yavaşla ve farlarını düzgün kullan."},
      19:{q:"İlerde fren lambaları ve yavaşlayan trafik görüyorsun. Ne yapmalısın?",options:["Hızını aynen sabit korumak","Erkenden gazdan çekip yavaşlamaya hazırlanmak","Onların hepsini geçmek için hızlanmak","Çok hızlı şekilde şerit değiştirmek"],explanation:"Erkenden gazdan çek ve yumuşakça yavaşlamaya hazırlan."},
      20:{q:"İlerde bir yaya kaldırımdan caddeye iniyor. Ne yapmalısın?",options:["Korna çalıp devam etmek","Yavaşlayıp durmaya hazır olmak","Önce geçmek için hızlanmak","Karşı trafiğe kaçmak"],explanation:"Yaya için yavaşla ve durmaya hazır ol."},
      21:{q:"Şerit değiştirmek istiyorsun ama kör noktanda bir araba var. Ne yapmalısın?",options:["Yine de geçmek","Temiz bir boşluk bekleyip tekrar kontrol etmek","Hızlanıp zorla girmek","Biraz yer açmak için frenlemek"],explanation:"Temiz bir boşluk bekle, aynaları ve kör noktayı tekrar kontrol et."},
      22:{q:"Başka bir sürücüye karşı öfken artıyor. Güvenli seçim nedir?",options:["Onunla doğrudan yüzleşip kavga etmek","Sakin kalmak, mesafe tutmak ve karışmamak","Önündeki yolunu kesmek","Ona sert fren-check yapmak"],explanation:"Sakin kal, mesafe tut ve karışma."},
      23:{q:"Yoğun bir otoyolda güvenle şerit değiştirmek için ne yapmalısın?",options:["Çok hızlı bir şekilde geçmek","Sinyal verip aynaları ve kör noktaları kontrol edip temizken geçmek","Sinyalsiz yavaşça kayıp geçmek","Önce sertçe frenleyip ardından geçip gitmek"],explanation:"Sinyal ver, aynaları ve kör noktaları kontrol et, temizken geç."}
