      12:{q:"Texas'ta emniyetsiz yükü dökülen bir sürücü nasıldır?",options:["Asla kusurlu değil","Sorumlu ve ceza alabilir","Küçük ödül alır","Her zaman mazur"],explanation:"Sürücü sorumludur ve ceza alabilir."},
      13:{q:"DPS kamyonunu bir Texas denetim istasyonuna alırsa ne yapmalısın?",options:["Geçip gitmek","Durup uymak","Hızlanıp ayrılmak","Hızla geri dönmek"],explanation:"Durmalı ve denetime uymalısın."},
      14:{q:"Texas'ta neyi kullanan bir yayaya her zaman yol vermelisin?",options:["Parlak kırmızı şapka","Beyaz baston ya da rehber köpek","Mavi şemsiye","Yüksek düdük"],explanation:"Beyaz baston ya da rehber köpekli yayaya her zaman yol ver."},
      15:{q:"Bir Texas okul bölgesinde neye uymalısın?",options:["Normal otoyol hızına","Düşük yazılı hız limitine","Kamyona özel hızlı şerit","Limitsiz hız kuralına"],explanation:"Düşük okul bölgesi hız limitine uy."},
      16:{q:"Texas neyden önce sinyal vermeni ister?",options:["Sadece sağ dönüş","Her şerit değişimi","Sadece U dönüşü","Hiç gerekmez"],explanation:"Her şerit değişimi ve dönüşten önce sinyal ver."},
      17:{q:"Bir Texas demiryolu geçidinde durmaman gerekir çünkü:",options:["Daha rahat","Bir tren seni orada sıkıştırabilir","Yakıt tasarrufu","Bir kestirme"],explanation:"Bir tren gelip seni geçitte sıkıştırabilir."},
      18:{q:"Texas'ta trafik dururken bir kavşağı kapamak nasıldır?",options:["Akıllıca bir hamle","İzin verilmez","Her zaman sorun yok","Tavsiye edilir"],explanation:"Kavşağı kapama; izin verilmez."},
      19:{q:"Texas'ta kamyonundan çöp/atık atmak neye yol açabilir?",options:["Teşekkür notu","Bir para cezası","Ücretsiz yıkama","Bir nakit ödül"],explanation:"Araçtan çöp atmak para cezası getirebilir."},
      20:{q:"Texas çalışan fren lambası ister ki başkaları senin ne yaptığını bilsin:",options:["Radyoyu açtığını","Yavaşladığını ya da durduğunu","Yan cam açtığını","Kanal değiştirdiğini"],explanation:"Fren lambaları yavaşladığını ya da durduğunu uyarır."},
      21:{q:"Bir Texas kavşağında sola dönmek için kime yol vermelisin?",options:["Hiç kimseye","Karşıdan gelen trafiğe","Park etmiş arabalara","Açık gökyüzüne"],explanation:"Sola dönmeden önce karşı trafiğe yol ver."},
      22:{q:"Bir Texas CDL adayı önce neyi geçmeli?",options:["Yüzme testi","Gerekli bilgi testlerini","Yazma testi","Göz rengi testi"],explanation:"Gerekli bilgi testlerini geçmelisin."},
      23:{q:"Texas'ta neyin türünü kendin beyan etmen (self-certify) gerekir?",options:["Sevdiğin müziğin","Yaptığın sürüşün","Yediğin yemeğin","Kamyon renginin"],explanation:"Tıbbi kurallar için yaptığın sürüş türünü beyan et."}
