      0:{q:"Техас требует, чтобы держатель CDL имел права при себе:",options:["Только по выходным","Всегда при управлении коммерческим ТС","Только за пределами штата","Только при проверках"],explanation:"Вози CDL всегда, когда управляешь CMV."},
      1:{q:"Чтобы водить CMV только внутри Техаса (intrastate), минимальный возраст:",options:["16","18","21","25"],explanation:"Для внутриштатного CMV — 18 лет."},
      2:{q:"Чтобы водить CMV между штатами (interstate), минимальный возраст:",options:["18","21","25","16"],explanation:"Для межштатного CMV — 21 год."},
      3:{q:"Минимальная страховка ответственности в Техасе за травму одного человека:",options:["10 000 $","30 000 $","5 000 $","100 000 $"],explanation:"Минимум Техаса — 30 000 $ на пострадавшего."},
      4:{q:"Отказ от обязательного теста крови или дыхания в Техасе ведёт к:",options:["Лишь к письменному предупреждению","Автоматическому лишению прав","Быстрой бесплатной пересдаче","Ничему вообще"],explanation:"Отказ ведёт к автоматическому лишению прав."},
      5:{q:"В Техасе автобусы и табличный hazmat-транспорт всегда должны:",options:["Проскакивать переезды","Останавливаться на ж/д переездах","Пропускать весовую","Игнорировать сигналы поезда"],explanation:"Они обязаны останавливаться на ж/д переездах."},
      6:{q:"Техасский 'основной закон скорости' гласит, что скорость должна быть:",options:["Всегда ровно по лимиту","Разумной и осторожной под условия","Как можно выше","Какой захочешь"],explanation:"Скорость должна быть разумной и осторожной под условия."},
      7:{q:"Ехать слишком медленно и мешать обычному движению в Техасе:",options:["Хорошая идея","Не разрешено","Всегда обязательно","Поощряется"],explanation:"Мешать движению слишком медленной ездой нельзя."},
      8:{q:"На многополосной трассе Техаса медленные грузовики обычно должны:",options:["Держать крайний левый","Держаться правее","Петлять по полосам","Останавливаться на дороге"],explanation:"Медленные ТС должны держаться правее."},
      9:{q:"В Техасе обгонять справа можно только когда:",options:["Как захочешь","Это безопасно и не по обочине","Трафик очень плотный","Ты торопишься"],explanation:"Обгоняй справа только безопасно и никогда не по обочине."},
      10:{q:"Техасской похоронной процессии нужно:",options:["Быстро проехать сквозь","Уступить дорогу","Обогнать справа","Громко сигналить"],explanation:"Уступи дорогу похоронной процессии."},
      11:{q:"В Техасе ребёнок до 8 лет (и ниже 4'9\") должен ехать в:",options:["На переднем сиденье","Детском кресле","Совсем без кресла","Грузовом отсеке"],explanation:"Маленькие невысокие дети — в детском кресле."},
      12:{q:"Водитель, чей незакреплённый груз рассыпался, в Техасе:",options:["Никогда не виноват","Отвечает и может быть оштрафован","Получает награду","Всегда оправдан"],explanation:"Водитель отвечает и может быть оштрафован."},
      13:{q:"Если DPS направляет твой грузовик на инспекцию в Техасе, нужно:",options:["Проехать мимо","Остановиться и подчиниться","Ускориться и уехать","Быстро развернуться"],explanation:"Нужно остановиться и пройти инспекцию."},
      14:{q:"В Техасе всегда нужно уступать пешеходу, использующему:",options:["Ярко-красную шляпу","Белую трость или собаку-поводыря","Синий зонт","Громкий свисток"],explanation:"Всегда уступай пешеходу с белой тростью или собакой-поводырём."},
      15:{q:"В школьной зоне Техаса нужно соблюдать:",options:["Обычную скорость трассы","Пониженный указанный лимит","Скоростную полосу для грузовиков","Правило без лимита"],explanation:"Соблюдай пониженный лимит школьной зоны."},
      16:{q:"Техас требует подавать сигнал перед:",options:["Только правыми поворотами","Каждой сменой полосы","Только разворотами","Никогда"],explanation:"Сигналь перед каждой сменой полосы и поворотом."},
      17:{q:"Нельзя останавливаться на ж/д переезде в Техасе, потому что:",options:["Так удобнее","Поезд может тебя запереть","Это экономит топливо","Это короткий путь"],explanation:"Поезд может подойти и запереть тебя на переезде."},
      18:{q:"Перекрывать перекрёсток при остановившемся движении в Техасе:",options:["Умный ход","Не разрешено","Всегда нормально","Рекомендуется"],explanation:"Не перекрывай перекрёсток; это не разрешено."},
      19:{q:"Мусор или обломки, падающие с твоего грузовика в Техасе, грозят:",options:["Благодарностью","Штрафом","Бесплатной мойкой","Денежной наградой"],explanation:"Мусор с машины грозит штрафом."},
      20:{q:"Техас требует рабочие стоп-сигналы, чтобы другие знали, когда ты:",options:["Включаешь радио","Замедляешься или тормозишь","Открываешь окно","Меняешь канал"],explanation:"Стоп-сигналы предупреждают, что ты замедляешься или тормозишь."},
      21:{q:"Чтобы повернуть налево на перекрёстке Техаса, нужно уступить:",options:["Никому","Встречному движению","Припаркованным машинам","Открытому небу"],explanation:"Перед левым поворотом уступи встречным."},
