      {q:"A crossing guard's stop signal in Texas must be:",options:["Ignored fully","Obeyed","Argued with","Honked at"],answer:1,explanation:"Obey a crossing guard's stop signal.",handbook:"Obey a school crossing guard's stop signal.",hbref:"§14"},
      {q:"You should never shift gears while on:",options:["A flat highway","Railroad tracks","A long bridge","An on-ramp"],answer:1,explanation:"Don't shift gears on railroad tracks.",handbook:"Never shift gears while on railroad tracks.",hbref:"§14"},
      {q:"In Texas, leaving a young child alone in a vehicle is:",options:["Perfectly fine","Illegal","Encouraged","Smart"],answer:1,explanation:"Leaving a young child alone in a vehicle is illegal.",handbook:"It is illegal to leave a young child alone in a vehicle.",hbref:"§14"},
      {q:"A transit bus signaling to re-enter traffic in Texas should be:",options:["Blocked off","Allowed to merge","Honked at","Passed fast"],answer:1,explanation:"Let a transit bus merge back into traffic.",handbook:"Yield to a transit bus signaling to re-enter traffic.",hbref:"§14"},
      {q:"Keeping an 'assured clear distance' means leaving enough room to:",options:["Carry more cargo","Stop safely","Drive much faster","Save more fuel"],answer:1,explanation:"Keep enough room to stop safely.",handbook:"Assured clear distance means room to stop safely.",hbref:"§14"},
      {q:"Making a U-turn where a sign prohibits it is:",options:["A good shortcut","Illegal","Encouraged","Required"],answer:1,explanation:"A U-turn where prohibited is illegal.",handbook:"Do not make a U-turn where a sign prohibits it.",hbref:"§14"},
      {q:"The Texas littering fine for dumping from a vehicle can be:",options:["A few cents","Several hundred dollars","Totally free","A small thank-you"],answer:1,explanation:"Littering from a vehicle can cost several hundred dollars.",handbook:"Littering from a vehicle can bring fines of several hundred dollars.",hbref:"§14"},
      {q:"A truck taller than 13'6\" must especially watch for:",options:["Wide open fields","Low bridges and overpasses","Empty parking lots","Smooth flat roads"],answer:1,explanation:"Watch for low bridges and overpasses.",handbook:"Tall vehicles must watch for low bridges and overpasses.",hbref:"§14"},
      {q:"Texas school-zone phone rules apply when the lights are:",options:["Switched off","Flashing","Painted red","Brand new"],answer:1,explanation:"The phone rules apply when the lights are flashing.",handbook:"School-zone phone bans apply when the lights are flashing.",hbref:"§14"},
      {q:"In Texas, dim your high beams within ___ of an oncoming vehicle.",options:["50 feet","500 feet","2 miles","5 feet"],answer:1,explanation:"Dim within 500 feet of an oncoming vehicle.",handbook:"Dim high beams within 500 feet of an oncoming vehicle.",hbref:"§14"},
      {q:"When following another vehicle at night, dim your high beams within:",options:["30 feet","300 feet","3 miles","3 feet"],answer:1,explanation:"Dim within 300 feet when following another vehicle.",handbook:"Dim high beams within 300 feet when following another vehicle.",hbref:"§14"},
      {q:"A driver who keeps driving a vehicle placed out of service:",options:["Did the right thing","Breaks the law","Saves the day","Gets a reward"],answer:1,explanation:"Driving an out-of-service vehicle breaks the law.",handbook:"It is illegal to drive a vehicle placed out of service.",hbref:"§14"},
      {q:"Texas requires your turn signals and brake lights to be:",options:["Painted over","Working","Removed","Disconnected"],answer:1,explanation:"Turn signals and brake lights must be working.",handbook:"Turn signals and brake lights must be in working order.",hbref:"§14"},
      {q:"Before entering a Texas roundabout, you must yield to vehicles:",options:["Far behind you","Already in it","Across town","On the sidewalk"],answer:1,explanation:"Yield to vehicles already in the roundabout.",handbook:"Yield to vehicles already in a roundabout before entering.",hbref:"§14"},
      {q:"A CDL is required in Texas to drive a single vehicle with a GVWR of:",options:["10,000 lb or more","26,001 lb or more","5,000 lb or more","1,000 lb or more"],answer:1,explanation:"A CDL is required for a single vehicle rated 26,001 lb or more.",handbook:"A CDL is required for a single vehicle with a GVWR of 26,001 lb or more.",hbref:"§14"}
