      17:{q:"Разворот там, где знак его запрещает:",options:["Хороший срез пути","Незаконен","Поощряется","Обязателен"],explanation:"Разворот в запрещённом месте незаконен."},
      18:{q:"Штраф за мусор из машины в Техасе может составить:",options:["Пару центов","Несколько сотен долларов","Совсем бесплатно","Маленькую благодарность"],explanation:"Штраф за мусор из машины может быть несколько сотен долларов."},
      19:{q:"Грузовик выше 13'6\" должен особенно следить за:",options:["Широкими полями","Низкими мостами и путепроводами","Пустыми стоянками","Ровными гладкими дорогами"],explanation:"Следи за низкими мостами и путепроводами."},
      20:{q:"Правила о телефоне в школьной зоне Техаса действуют, когда огни:",options:["Выключены","Мигают","Покрашены красным","Совсем новые"],explanation:"Правила действуют, когда огни мигают."},
      21:{q:"В Техасе переключай дальний на ближний за ___ до встречного.",options:["50 футов","500 футов","2 мили","5 футов"],explanation:"Переключай за 500 футов до встречного."},
      22:{q:"Следуя ночью за другой машиной, переключай дальний свет за:",options:["30 футов","300 футов","3 мили","3 фута"],explanation:"Следуя за машиной, переключай за 300 футов."},
      23:{q:"Водитель, продолжающий вести ТС, выведенное из эксплуатации:",options:["Поступил правильно","Нарушает закон","Спас положение","Получает награду"],explanation:"Вести ТС, выведенное из эксплуатации, — нарушение закона."},
      24:{q:"Техас требует, чтобы указатели поворота и стоп-сигналы были:",options:["Закрашены","Рабочими","Сняты","Отключены"],explanation:"Указатели и стоп-сигналы должны быть рабочими."},
      25:{q:"Перед въездом на круг в Техасе нужно уступить машинам:",options:["Далеко позади","Уже на кругу","На другом конце города","На тротуаре"],explanation:"Уступи тем, кто уже на кругу."},
      26:{q:"В Техасе CDL нужен для одиночного ТС с GVWR:",options:["10 000 фунтов и более","26 001 фунт и более","5 000 фунтов и более","1 000 фунтов и более"],explanation:"CDL нужен для одиночного ТС от 26 001 фунта."}
