      2:{q:"Çekici koruma valfi hava yaklaşık kaça düşünce otomatik kapanır?",options:["80-90 psi","20-45 psi","100-120 psi","tam 150 psi"],explanation:"Yaklaşık 20-45 psi'de kapanır."},
