      17:{q:"Hava freni temeli kampana, balata ve neyi içerir?",options:["Radyolar","Slack ayarlayıcılar","Aynalar","Koltuklar"],explanation:"Slack ayarlayıcıları da içerir."},
      18:{q:"Bir glad hand tıslıyorsa ortada ne vardır?",options:["Daha çok güç","Hava kaçağı","Temiz hat","İyi conta"],explanation:"Bir hava kaçağı vardır."},
      19:{q:"ABS ile acil durumda nasıl frenlersin?",options:["Hızlı pompalayarak","Sıkıca basıp basılı tutarak","Bir kez dokunarak","Korna kullanarak"],explanation:"Sıkıca bas ve basılı tut."},
      20:{q:"Tanklardaki su ve yağ ne yapabilir?",options:["Frenlere yardım eder","Fren sistemine zarar verir","Güç ekler","Yakıt biriktirir"],explanation:"Fren sistemine zarar verebilir."},
      21:{q:"Islak tank neyiyle boşaltılır?",options:["Direksiyonla","Tahliye valfi (petcock)","Gaz pedalıyla","Kapı koluyla"],explanation:"Tahliye valfiyle (petcock) boşaltılır."},
      22:{q:"Hava bırakan bir emniyet valfi basıncın ne olduğunu gösterir?",options:["Çok düşük","Çok yüksek","Tam kararında","Donmuş"],explanation:"Basıncın çok yükseldiğini gösterir."},
      23:{q:"Yay frenlerine başka ne ad verilir?",options:["Mini-fren","Maxi-fren","Disk-fren","El-freni"],explanation:"Yay frenlerine maxi-fren de denir."},
      24:{q:"Hava frenlerini öğrenmenin ana nedeni nedir?",options:["Daha hızlı sürmek","Ağır aracı güvenle durdurmak","Sadece yakıt","Becerikli görünmek"],explanation:"Ağır bir aracı güvenle durdurmak içindir."}
