      11:{q:"Если после запуска лампа ABS прицепа горит, ABS прицепа может:",options:["Отлично работать","Не работать","Быть новой","Быть заряженной"],explanation:"ABS прицепа может не работать."},
      12:{q:"При расцепке опорные ноги нельзя опускать:",options:["На твёрдый грунт","На мягкий грунт","На ровный грунт","На асфальт"],explanation:"Не опускай на мягкий грунт."},
