      20:{q:"Прицеп с плохим шнуром освещения может потерять:",options:["Грузовые двери","Стоп- и поворотные огни","Запаску","Брызговики"],explanation:"Может потерять стоп- и поворотные огни."},
      21:{q:"Сцепку труднее сдавать назад, потому что она:",options:["Очень короткая","Складывается посередине","Без тормозов","Ничего не весит"],explanation:"Потому что складывается посередине."},
